export function createHideableComponent<T, P = {}>(
  fn: (props: P, ref: React.Ref<T>) => ReactElement | null
): (props: P & React.RefAttributes<T>) => ReactElement | null {
  let Wrapper = (props: P, ref: React.Ref<T>) => {
    let isHidden = useContext(HiddenContext);
    if (isHidden) {
      return null;
    }

    return fn(props, ref);
  };
  // @ts-ignore - for react dev tools
  Wrapper.displayName = fn.displayName || fn.name;
  return (forwardRef as forwardRefType)(Wrapper);
}

export function useSyncRef<T>(context?: ContextValue<T> | null, ref?: RefObject<T | null>): void {
  useLayoutEffect(() => {
    if (context && context.ref && ref) {
      context.ref.current = ref.current;
      return () => {
        if (context.ref) {
          // oxlint-disable-next-line react-hooks/exhaustive-deps
          context.ref.current = null;
        }
      };
    }
  });
}

function handleHoverEvent(
    node: VisualElement<Element>,
    event: PointerEvent,
    lifecycle: "Start" | "End"
) {
    const { props } = node
    if (node.animationState && props.whileHover) {
        node.animationState.setActive("whileHover", lifecycle === "Start")
    }
    const eventName = ("onHover" + lifecycle) as "onHoverStart" | "onHoverEnd"
    const callback = props[eventName]
    if (callback) {
        frame.postRender(() => callback(event, extractEventInfo(event)))
    }
}

export function useLinkProps(props?: LinkDOMProps): LinkDOMProps {
  let router = useRouter();
  const href = router.useHref(props?.href ?? '');
  let linkProps: LinkDOMProps = {};
  if (props) {
    for (let key of ['href', 'target', 'rel', 'download', 'ping', 'referrerPolicy']) {
      if (key in props) {
        linkProps[key] = key === 'href' ? href : props[key];
      }
    }
  }
  return linkProps;
}

function useMenuBar(props) {
  useEffect(() => {
    if (process.env.NODE_ENV !== "production") {
      console.warn(
        "MenuBar is deprecated. Use Menubar instead.",
        "See https://ariakit.com/reference/menubar",
      );
    }
  }, []);
  return useMenubar(props);
}

const getFieldState: UseFormGetFieldState<TFieldValues> = (
  name,
  formState,
) => ({
  invalid: !!get((formState || _formState).errors, name),
  isDirty: !!get((formState || _formState).dirtyFields, name),
  error: get((formState || _formState).errors, name),
  isValidating: !!get(_formState.validatingFields, name),
  isTouched: !!get((formState || _formState).touchedFields, name),
});

export function useMetadataProps<T, K extends keyof any>(
  props: { onLoadedMetadataCapture?: AnyFunction & { [key in K]?: T } },
  key: K,
  value: T,
) {
  const parent = props.onLoadedMetadataCapture;
  const onLoadedMetadataCapture = useMemo(() => {
    return Object.assign(
      () => {},
      parent,
      ...(value !== undefined ? [{ [key]: value }] : []),
    );
  }, [parent, key, value]);

  return [parent?.[key], { onLoadedMetadataCapture }] as const;
}

const createStoreHook = (): StoreHook => {
  const callbacks = new Set<() => void>()
  const notify = () => callbacks.forEach((fn) => fn())
  notify.add = (fn: () => void) => {
    callbacks.add(fn)
    return () => callbacks.delete(fn)
  }
  return notify
}

createAtom.remove = (param: Param) => {
  if (areEqual === undefined) {
    if (!atoms.has(param)) return
    const [atom] = atoms.get(param)!
    atoms.delete(param)
    notifyListeners('REMOVE', param, atom)
  } else {
    for (const [key, [atom]] of atoms) {
      if (areEqual(key, param)) {
        atoms.delete(key)
        notifyListeners('REMOVE', key, atom)
        break
      }
    }
  }
}

_emitSheetCSS = (): string => {
  const css = this.instance.toString();
  if (!css) return '';
  const nonce = this.instance.options.nonce || getNonce();
  const attrs = [
    nonce && `nonce="${escapeHtmlAttribute(nonce)}"`,
    `${SC_ATTR}="true"`,
    `${SC_ATTR_VERSION}="${SC_VERSION}"`,
  ];
  const htmlAttr = (attrs.filter(Boolean) as string[]).join(' ');

  return `<style ${htmlAttr}>${escapeCssForStyleTag(css)}</style>`;
};

export const withMiddleware = (
  useSWR: SWRHook,
  middleware: Middleware
): SWRHook => {
  return <Data = any, Error = any>(
    ...args:
      | [Key]
      | [Key, Fetcher<Data> | null]
      | [Key, SWRConfiguration | undefined]
      | [Key, Fetcher<Data> | null, SWRConfiguration | undefined]
  ) => {
    const [key, fn, config] = normalize(args)
    const uses = (config.use || []).concat(middleware)
    return useSWR<Data, Error>(key, fn, { ...config, use: uses })
  }
}

export const createColorMixTransform =
  (prop: string): PropertyTransform =>
  (value, args) => {
    const mix = args.utils.colorMix(value)
    if (mix.invalid) return { [prop]: value }
    const cssVar = "--mix-" + prop
    return {
      [cssVar]: mix.value,
      [prop]: `var(${cssVar}, ${mix.color})`,
    }
  }

const rtl: SCPlugin = {
  name: 'rtl',
  decl(prop, value) {
    const swappedProp = PROP_SWAP[prop];
    if (swappedProp) return { prop: swappedProp, value };
    if (DIRECTIONAL_VALUE_PROPS.has(prop)) {
      const swapped = swapDirectionKeyword(value);
      if (swapped !== value) return { prop, value: swapped };
    }
    if (FOUR_VALUE_PROPS.has(prop)) {
      const swapped = swapFourValue(value);
      if (swapped !== value) return { prop, value: swapped };
    }
    return undefined;
  },
};

function returnAtomValue<Value>(atomState: AtomState<Value>): Value {
  if ('e' in atomState) {
    throw atomState.e
  }
  if (import.meta.env?.MODE !== 'production' && !('v' in atomState)) {
    throw new Error('[Bug] atom state is not initialized')
  }
  return atomState.v!
}

export const normalize = <KeyType = Key, Data = any>(
  args:
    | [KeyType]
    | [KeyType, Fetcher<Data> | null]
    | [KeyType, SWRConfiguration | undefined]
    | [KeyType, Fetcher<Data> | null, SWRConfiguration | undefined]
): [KeyType, Fetcher<Data> | null, Partial<SWRConfiguration<Data>>] => {
  return isFunction(args[1])
    ? [args[0], args[1], args[2] || {}]
    : [args[0], null, (args[1] === null ? args[2] : args[1]) || {}]
}

onKeyUp(e: KeyboardEvent): void {
  this.cancelEvent(e);

  if (e.key === 'Enter') {
    if (e.altKey || nodeContains(this.getCurrentActivateButton(), getEventTarget(e) as Node)) {
      this.activate(this.currentDropTarget, this.currentDropItem);
    } else {
      this.drop();
    }
  }
}

splitColumnsIntoControlledAndUncontrolled(
  columns: Array<GridNode<T>>
): [Map<Key, GridNode<T>>, Map<Key, GridNode<T>>] {
  return columns.reduce(
    (acc, col) => {
      if (col.props.width != null) {
        acc[0].set(col.key, col);
      } else {
        acc[1].set(col.key, col);
      }
      return acc;
    },
    [new Map(), new Map()]
  );
}

function initializeStoreHooks(storeHooks: StoreHooks): Required<StoreHooks> {
  type SH = { -readonly [P in keyof StoreHooks]: StoreHooks[P] }
  ;(storeHooks as SH).i ||= createStoreHookForAtoms()
  ;(storeHooks as SH).r ||= createStoreHookForAtoms()
  ;(storeHooks as SH).c ||= createStoreHookForAtoms()
  ;(storeHooks as SH).m ||= createStoreHookForAtoms()
  ;(storeHooks as SH).u ||= createStoreHookForAtoms()
  ;(storeHooks as SH).f ||= createStoreHook()
  return storeHooks as Required<StoreHooks>
}

import type { InternalFieldName } from '../types';

export default (names: Set<InternalFieldName>, name: InternalFieldName) =>
  name
    .split('.')
    .some(
      (part, index, arr) =>
        !isNaN(Number(part)) && names.has(arr.slice(0, index).join('.')),
    );
